  1	import * as React from 'react';
  2	import {
  3	  DRApplication,
  4	  AssignPolicySteps,
  5	  AssignPolicyStepsNames,
  6	} from '@odf/mco/constants';
  7	import { requirementFromString } from '@odf/shared/modals';
  8	import { getName } from '@odf/shared/selectors';
  9	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 10	import { Operator } from '@openshift-console/dynamic-plugin-sdk';
 11	import * as _ from 'lodash-es';
 12	import { TFunction } from 'react-i18next';
 13	import { useWizardContext, WizardFooterWrapper } from '@patternfly/react-core';
 14	import {
 15	  Button,
 16	  Alert,
 17	  AlertVariant,
 18	  AlertProps,
 19	} from '@patternfly/react-core';
 20	import { AssignPolicyViewState, PVCSelectorType } from '../utils/reducer';
 21	import { DRPolicyType } from '../utils/types';
 22	import '../../../../style.scss';
 23	import '../style.scss';
 24	
 25	export const getLabelValidationMessage = (t: TFunction) =>
 26	  t(
 27	    'Labels must start and end with an alphanumeric character, can consist of lower-case letters, numbers, dots (.), hyphens (-), forward slash (/), underscore(_) and equal to (=)'
 28	  );
 29	
 30	export const isValidLabelInput = (labels: string[] = []): boolean =>
 31	  labels.length
 32	    ? labels.every((label) => {
 33	        const requirement = requirementFromString(label);
 34	        // "key" or "key=value" is supported
 35	        return (
 36	          !!requirement &&
 37	          [Operator.Equals, Operator.Exists].includes(
 38	            requirement?.operator as Operator
 39	          )
 40	        );
 41	      })
 42	    : false;
 43	
 44	const isPVCSelectorFound = (pvcSelectors: PVCSelectorType[]) =>
 45	  !!pvcSelectors.length &&
 46	  !!pvcSelectors.every(
 47	    (pvcSelector) =>
 48	      !!pvcSelector.placementName && isValidLabelInput(pvcSelector.labels)
 49	  );
 50	
 51	const isDRPolicySelected = (dataPolicy: DRPolicyType) => !!getName(dataPolicy);
 52	
 53	const validateReplicationStep = (
 54	  policy: DRPolicyType,
 55	  k8sSyncInterval: string
 56	) =>
 57	  !_.isEmpty(policy) &&
 58	  k8sSyncInterval !== undefined &&
 59	  k8sSyncInterval !== '0m';
 60	
 61	const validateProtectionTypeStep = (
 62	  protectionName: string,
 63	  appType: DRApplication
 64	) => !!appType && (appType !== DRApplication.DISCOVERED || !!protectionName);
 65	
 66	const canJumpToNextStep = (
 67	  stepName: string,
 68	  state: AssignPolicyViewState,
 69	  appType: DRApplication,
 70	  t: TFunction
 71	) => {
 72	  switch (stepName) {
 73	    case AssignPolicyStepsNames(t)[AssignPolicySteps.Policy]:
 74	      return isDRPolicySelected(state.policy);
 75	    case AssignPolicyStepsNames(t)[AssignPolicySteps.PersistentVolumeClaim]:
 76	      return isPVCSelectorFound(state.persistentVolumeClaim.pvcSelectors);
 77	    case AssignPolicyStepsNames(t)[AssignPolicySteps.ProtectionType]:
 78	      return validateProtectionTypeStep(
 79	        state.protectionType.protectionName,
 80	        appType
 81	      );
 82	    case AssignPolicyStepsNames(t)[AssignPolicySteps.Replication]:
 83	      return validateReplicationStep(
 84	        state.replication.policy,
 85	        state.replication.k8sSyncInterval
 86	      );
 87	    default:
 88	      return false;
 89	  }
 90	};
 91	
 92	const getErrorMessage = (
 93	  state: AssignPolicyViewState,
 94	  stepName: string,
 95	  errorMessage: string,
 96	  t: TFunction
 97	): AlertProps => {
 98	  const defualtMessage = {
 99	    title: t(
100	      '1 or more mandatory fields are empty. To proceed, fill in the required information.'
101	    ),
102	    variant: AlertVariant.danger,
103	  };
104	  switch (stepName) {
105	    case AssignPolicyStepsNames(t)[AssignPolicySteps.ReviewAndAssign]:
106	      return {
107	        title: errorMessage,
108	        variant: AlertVariant.danger,
109	      };
110	    case AssignPolicyStepsNames(t)[AssignPolicySteps.PersistentVolumeClaim]: {
111	      const { pvcSelectors } = state.persistentVolumeClaim;
112	      const isValidPVCSelector = pvcSelectors.every((pvcSelector) =>
113	        pvcSelector.labels.length ? isValidLabelInput(pvcSelector.labels) : true
114	      );
115	      return !isValidPVCSelector
116	        ? {
117	            title: t('Invalid label selector'),
118	            children: t(
119	              "The selected PVC label selector doesn't meet the label requirements. Choose a valid label selector or create one with the following requirements: {{ message }}",
120	              { message: getLabelValidationMessage(t) }
121	            ),
122	            variant: AlertVariant.danger,
123	          }
124	        : defualtMessage;
125	    }
126	    default:
127	      return defualtMessage;
128	  }
129	};
130	
131	export const AssignPolicyViewFooter: React.FC<AssignPolicyViewFooterProps> = ({
132	  state,
133	  appType,
134	  isValidationEnabled,
135	  errorMessage,
136	  onSubmit,
137	  onCancel,
138	  setIsValidationEnabled,
139	}) => {
140	  const { t } = useCustomTranslation();
141	  const [requestInProgress, setRequestInProgress] = React.useState(false);
142	  const { activeStep, goToNextStep, goToPrevStep } = useWizardContext();
143	
144	  const stepName = activeStep.name as string;
145	
146	  const canJumpToNext = canJumpToNextStep(stepName, state, appType, t);
147	  const validationError = isValidationEnabled && !canJumpToNext;
148	  const message =
149	    (validationError || !!errorMessage) &&
150	    getErrorMessage(state, stepName, errorMessage, t);
151	
152	  const moveToNextStep = () => {
153	    if (canJumpToNext) {
154	      goToNextStep();
155	      setIsValidationEnabled(false);
156	    } else {
157	      setIsValidationEnabled(true);
158	    }
159	  };
160	
161	  const handleNext = async () => {
162	    switch (stepName) {
163	      case AssignPolicyStepsNames(t)[AssignPolicySteps.ReviewAndAssign]:
164	        setRequestInProgress(true);
165	        await onSubmit();
166	        setRequestInProgress(false);
167	        break;
168	      default:
169	        moveToNextStep();
170	    }
171	  };
172	
173	  return (
174	    <>
175	      {!!message && (
176	        <Alert
177	          title={message.title}
178	          variant={message.variant}
179	          isInline
180	          className="odf-alert mco-manage-policies__alert--margin-left"
181	        >
182	          {message?.children}
183	        </Alert>
184	      )}
185	      <WizardFooterWrapper>
186	        <Button
187	          isLoading={requestInProgress}
188	          isDisabled={requestInProgress || validationError}
189	          variant="primary"
190	          onClick={handleNext}
191	        >
192	          {stepName ===
193	          AssignPolicyStepsNames(t)[AssignPolicySteps.ReviewAndAssign]
194	            ? t('Assign')
195	            : t('Next')}
196	        </Button>
197	        {/* Disabling the back button for the first step (Policy) in wizard */}
198	        <Button
199	          variant="secondary"
200	          onClick={goToPrevStep}
201	          isDisabled={activeStep.index === 1 || requestInProgress}
202	        >
203	          {t('Back')}
204	        </Button>
205	        <Button
206	          variant="link"
207	          onClick={onCancel}
208	          isDisabled={requestInProgress}
209	        >
210	          {t('Cancel')}
211	        </Button>
212	      </WizardFooterWrapper>
213	    </>
214	  );
215	};
216	
217	type AssignPolicyViewFooterProps = {
218	  state: AssignPolicyViewState;
219	  appType: DRApplication;
220	  isValidationEnabled: boolean;
221	  errorMessage: string;
222	  onSubmit: () => Promise<void>;
223	  onCancel: () => void;
224	  setIsValidationEnabled: React.Dispatch<React.SetStateAction<boolean>>;
225	};

